import{_ as e,o as a,c as o,a2 as r}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"Job tracking","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/jobs.md","filePath":"en/guide/jobs.md"}'),n={name:"en/guide/jobs.md"};function i(s,t,l,d,c,h){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="job-tracking" tabindex="-1">Job tracking <a class="header-anchor" href="#job-tracking" aria-label="Permalink to &quot;Job tracking&quot;">​</a></h1><p>All long-running operations in Nid (bulk deletion, archiving, newsletter scanning, etc.) are executed in the background via <strong>jobs</strong>. The Jobs page lets you track their progress.</p><hr><h2 id="job-list" tabindex="-1">Job list <a class="header-anchor" href="#job-list" aria-label="Permalink to &quot;Job list&quot;">​</a></h2><p>The <strong>Jobs</strong> page displays all your jobs with their current status:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td>🟡 <strong>Pending</strong></td><td>The job is in the queue, not yet started</td></tr><tr><td>🔵 <strong>Running</strong></td><td>The job is currently executing</td></tr><tr><td>🟢 <strong>Completed</strong></td><td>The job finished successfully</td></tr><tr><td>🔴 <strong>Failed</strong></td><td>The job failed (3 automatic retries exhausted)</td></tr><tr><td>⚪ <strong>Cancelled</strong></td><td>The job was manually cancelled</td></tr></tbody></table><blockquote><p>📸 <em>Suggested screenshot: Jobs page with several jobs in different statuses</em></p></blockquote><hr><h2 id="job-types" tabindex="-1">Job types <a class="header-anchor" href="#job-types" aria-label="Permalink to &quot;Job types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Triggered by</th></tr></thead><tbody><tr><td><strong>Bulk operation</strong></td><td>Bulk actions in My emails (delete, label, etc.)</td></tr><tr><td><strong>Archiving</strong></td><td>Archiving to NAS from My emails</td></tr><tr><td><strong>Rule execution</strong></td><td>Manual or scheduled launch of a rule</td></tr><tr><td><strong>Newsletter scan</strong></td><td>Scan from the Newsletters page</td></tr><tr><td><strong>Tracking pixel scan</strong></td><td>Scan from the Privacy page</td></tr><tr><td><strong>PII scan</strong></td><td>Sensitive data scan from Privacy</td></tr><tr><td><strong>Archive encryption</strong></td><td>Encryption from Privacy</td></tr><tr><td><strong>Archive trash purge</strong></td><td>Daily scheduled job (configurable)</td></tr></tbody></table><hr><h2 id="real-time-tracking" tabindex="-1">Real-time tracking <a class="header-anchor" href="#real-time-tracking" aria-label="Permalink to &quot;Real-time tracking&quot;">​</a></h2><p>When a job is launched, a <strong>progress modal</strong> appears automatically:</p><ul><li>Progress bar (e.g.: 42/150 emails processed)</li><li>Completion percentage</li><li>Real-time status</li></ul><blockquote><p>📸 <em>Suggested screenshot: job progress modal with progress bar</em></p></blockquote><p>Updates are instant thanks to <strong>Server-Sent Events</strong> (SSE) — no need to refresh the page.</p><p>You can close the modal without interrupting the job. It continues in the background.</p><hr><h2 id="cancel-a-job" tabindex="-1">Cancel a job <a class="header-anchor" href="#cancel-a-job" aria-label="Permalink to &quot;Cancel a job&quot;">​</a></h2><p>To cancel a pending or running job:</p><ol><li>Click the <strong>Cancel</strong> button next to the job</li><li>The job moves to <strong>Cancelled</strong> status</li></ol><div class="warning custom-block"><p class="custom-block-title">Partial cancellation</p><p>Emails already processed before cancellation are not restored. For example, if 50 out of 100 emails were deleted when you cancel, the first 50 remain deleted.</p></div><hr><h2 id="job-details" tabindex="-1">Job details <a class="header-anchor" href="#job-details" aria-label="Permalink to &quot;Job details&quot;">​</a></h2><p>Click on a job to see its details:</p><ul><li>Operation type</li><li>Gmail account involved</li><li>Number of emails processed / total</li><li>Creation and completion date</li><li>Error message (in case of failure)</li></ul><hr><h2 id="automatic-retry" tabindex="-1">Automatic retry <a class="header-anchor" href="#automatic-retry" aria-label="Permalink to &quot;Automatic retry&quot;">​</a></h2><p>In case of errors (e.g.: Gmail API timeout), jobs are automatically retried up to <strong>3 times</strong> with exponential backoff:</p><ul><li>1st attempt: immediate</li><li>2nd attempt: after 2 seconds</li><li>3rd attempt: after 4 seconds</li><li>After 3 failures: the job moves to <strong>Failed</strong> status</li></ul><hr><h2 id="job-completion-notifications" tabindex="-1">Job completion notifications <a class="header-anchor" href="#job-completion-notifications" aria-label="Permalink to &quot;Job completion notifications&quot;">​</a></h2><p>When a job finishes (success or failure), you receive a notification:</p><ul><li><strong>In-app</strong>: in the notification bell (🔔)</li><li><strong>Toast</strong>: temporary pop-up at the bottom of the page (if enabled in <a href="./notifications.html">preferences</a>)</li><li><strong>Webhook</strong>: push to Discord, Slack, etc. (if <a href="./notifications.html#webhooks">configured</a>)</li></ul><hr><h2 id="archive-trash-configuration" tabindex="-1">Archive trash configuration <a class="header-anchor" href="#archive-trash-configuration" aria-label="Permalink to &quot;Archive trash configuration&quot;">​</a></h2><p>At the bottom of the Jobs page, a form lets you configure the <strong>automatic purge</strong> of the archive trash:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Automatic purge enabled</strong></td><td>Enables or disables the scheduled purge</td><td>Enabled</td></tr><tr><td><strong>Days before permanent deletion</strong></td><td>Number of days before trash emails are purged</td><td>30 days</td></tr></tbody></table><p>The purge job runs <strong>daily at 4 AM</strong> and permanently deletes emails that have been in the trash longer than the configured retention period.</p><blockquote><p>📸 <em>Suggested screenshot: trash configuration form at the bottom of the Jobs page</em></p></blockquote>',40)])])}const b=e(n,[["render",i]]);export{u as __pageData,b as default};
